#include <iostream>
#include <memory>

int main() {
    // Using unique_ptr for exclusive ownership
    std::unique_ptr<int> ptr(new int(42));
    std::cout << "Value: " << *ptr << std::endl;

    // Memory is automatically freed when ptr goes out of scope
    return 0;
}

In this example, `std::unique_ptr` ensures that the allocated integer is automatically deleted when `ptr` goes out of scope, preventing memory leaks.
